import{_ as e,o as r,c as o,a2 as d}from"./chunks/framework.c3r8iWL8.js";const g=JSON.parse('{"title":"Guide: Spec-Driven Development","description":"Reference template for AI-native enterprise delivery on AWS","frontmatter":{},"headers":[],"relativePath":"guides/spec-driven-development.md","filePath":"guides/spec-driven-development.md","lastUpdated":1782929962000}'),n={name:"guides/spec-driven-development.md"};function a(s,t,i,l,c,p){return r(),o("div",null,[...t[0]||(t[0]=[d('<h1 id="guide-spec-driven-development" tabindex="-1">Guide: Spec-Driven Development <a class="header-anchor" href="#guide-spec-driven-development" aria-label="Permalink to &quot;Guide: Spec-Driven Development&quot;">​</a></h1><p><strong>Decision:</strong> How tightly should specifications bind AI-generated implementation?</p><p>Related: <a href="./../developer-workflow.html">developer-workflow.md</a> · <a href="./../sops/SOP-004-implementation.html">SOP-004</a></p><hr><h2 id="contract-formats" tabindex="-1">Contract formats <a class="header-anchor" href="#contract-formats" aria-label="Permalink to &quot;Contract formats&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Format</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>OpenAPI 3.1</strong></td><td>HTTP APIs; tooling-rich; Schemathesis/Pact</td><td>Not ideal for gRPC-primary shops</td></tr><tr><td><strong>AsyncAPI</strong></td><td>Events, queues, WebSockets</td><td>Second spec to maintain</td></tr><tr><td><strong>Protobuf + buf</strong></td><td>Strong typing; gRPC</td><td>Steeper curve for REST teams</td></tr><tr><td><strong>Gherkin / BDD only</strong></td><td>PO-friendly acceptance</td><td>Ambiguous for AI codegen without API schema</td></tr><tr><td><strong>JSON Schema files</strong></td><td>Flexible</td><td>No single operation map</td></tr></tbody></table><p><strong>Recommended:</strong> OpenAPI for REST/HTTP; AsyncAPI when events are first-class; BDD scenarios <strong>linked</strong> to OpenAPI operations.</p><hr><h2 id="ai-codegen-binding-levels" tabindex="-1">AI codegen binding levels <a class="header-anchor" href="#ai-codegen-binding-levels" aria-label="Permalink to &quot;AI codegen binding levels&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Level</th><th>Description</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Strict</strong></td><td>No code until spec <code>approved</code></td><td>Highest quality bar</td><td>Slower for tiny fixes</td></tr><tr><td><strong>Moderate</strong></td><td>Spec approved for new endpoints; patches can lag 1 sprint</td><td>Balanced</td><td>Requires discipline</td></tr><tr><td><strong>Loose</strong></td><td>Spec optional; AI free-form</td><td>Maximum vibe velocity</td><td>Architecture and test debt</td></tr></tbody></table><p><strong>Recommended for enterprise:</strong> Strict for T1/T2 external APIs; moderate for internal tools.</p><hr><h2 id="test-binding" tabindex="-1">Test binding <a class="header-anchor" href="#test-binding" aria-label="Permalink to &quot;Test binding&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Approach</th><th>Pros</th><th>Cons</th></tr></thead><tbody><tr><td><strong>Contract tests from OpenAPI</strong></td><td>Catches spec/code drift</td><td>Doesn&#39;t cover all business logic</td></tr><tr><td><strong>AI-generated tests from spec</strong></td><td>Fast coverage</td><td>May assert implementation bugs</td></tr><tr><td><strong>Human-written tests only</strong></td><td>Trusted</td><td>Doesn&#39;t scale with AI output volume</td></tr></tbody></table><p><strong>Recommended:</strong> AI generates from spec; human reviews test PR; contract tests are merge gate.</p><hr><h2 id="pitfalls" tabindex="-1">Pitfalls <a class="header-anchor" href="#pitfalls" aria-label="Permalink to &quot;Pitfalls&quot;">​</a></h2><table tabindex="0"><thead><tr><th>Pitfall</th><th>Why it hurts</th><th>Mitigation</th></tr></thead><tbody><tr><td><strong>Spec after code</strong></td><td>Contract tests pass wrong behavior</td><td>Block impl PR without approved spec</td></tr><tr><td><strong>AI tests from implementation</strong></td><td>Tests encode the bug</td><td>Generate from OpenAPI, not from code</td></tr><tr><td><strong>Underspecified error models</strong></td><td>AI invents inconsistent errors</td><td>Standard error schema in OpenAPI</td></tr><tr><td><strong>Breaking change without version</strong></td><td>Consumers break silently</td><td>URL or header versioning policy in ADR</td></tr><tr><td><strong>Spec too large for agent context</strong></td><td>Partial implementation</td><td>Per-service specs; MCP <code>get_spec</code> by file</td></tr><tr><td><strong>&quot;Just fix it in code&quot; culture</strong></td><td>Spec becomes fiction</td><td>CI diff checks spec vs route registration</td></tr><tr><td><strong>No link to ADRs</strong></td><td>Same debate every quarter</td><td><code>x-adr</code> on operations</td></tr></tbody></table><hr><h2 id="recommended-starting-point" tabindex="-1">Recommended starting point <a class="header-anchor" href="#recommended-starting-point" aria-label="Permalink to &quot;Recommended starting point&quot;">​</a></h2><p>Approved OpenAPI per service → AI scaffolds handler + contract tests → developer steers within operation IDs → PR requires spec link.</p><hr><h2 id="related" tabindex="-1">Related <a class="header-anchor" href="#related" aria-label="Permalink to &quot;Related&quot;">​</a></h2><ul><li><a href="./planning-adr-specs.html">Planning, ADR &amp; specs</a> · <a href="./automated-testing-qa.html">Automated testing</a></li></ul>',24)])])}const m=e(n,[["render",a]]);export{g as __pageData,m as default};
